// JavaScript 物件
let obj = { name: 'Tom', age: 30 };

// JSON 格式（屬性名稱和字串都用雙引號）
// { "name": "Tom", "age": 30 }

let market = [
  { bossName: "Tom", isClose: false },
  { bossName: "John", isClose: true }
];

if (market[0].isClose === false) {
  console.log(market[0].bossName + " 營業中");
} else {
  console.log(market[0].bossName + " 已打烊");
}

let students = [
  { name: "小明", score: 85, isAbsent: false },
  { name: "小美", score: 45, isAbsent: false }
];

if (students[1].isAbsent === true) {
  console.log(students[1].name + " 未到考");
} else if (students[1].score >= 60) {
  console.log(students[1].name + " 及格");
} else {
  console.log(students[1].name + " 不及格");
}

